interface IProtocol { string Name { get; } string Read(); }

abstract class Device { public string Id; public string Name; public IProtocol Proto; public abstract string Check(); }

class DryerBox : Device {
    public override string Check() { return $"{Proto.Name}: {Proto.Read()}"; }
}

class ModbusProto : IProtocol {
    public string Name => "Modbus";
    public string Read() { return "temp=25.5"; }
}

var d = new DryerBox { Id="D1", Name="烘干箱", Proto=new ModbusProto() };
Print(d.Check());
